"""Entrypoint of the plugin for the classifiers that are specific to TensorFlow"""

import logging
from typing import Type, List

from geosat.psanp.abstractions.stage import Stage
from geosat.psanp.abstractions.stages import register_stage

logger = logging.getLogger(__name__)


def _register_stages() -> None:
    try:
        import tensorflow
    except ModuleNotFoundError:
        logger.info(
            "TensorFlow is not installed, skipping registering related stages. "
            "If you wish to activate those stages, "
            "run `pip install psanp[tensorflow]`"
        )
        return

    from psanp.classifiers.tensorflow.ato_post_processing_classifier import (
        AtoPostProcessingClassifier,
    )
    from psanp.classifiers.tensorflow.point_net_classifiers import (
        PointNetClassifier,
        PointNetRailClassifier,
    )
    from psanp.classifiers.tensorflow.rosaline_classifier import RosalineClassifier
    from psanp.classifiers.tensorflow.susann_classifier import SusannClassifier
    from psanp.classifiers.tensorflow.susann_v2_classifier import SusannV2Classifier

    _STAGES: List[Type[Stage]] = [
        AtoPostProcessingClassifier,
        SusannClassifier,
        PointNetClassifier,
        PointNetRailClassifier,
        RosalineClassifier,
        SusannV2Classifier,
    ]

    logger.info(f"Registering {len(_STAGES)} TensorFlow stage(s)")
    for stage_class in _STAGES:
        register_stage(stage_class)


_register_stages()
